```python
def fizz_buzz(n: int) -> str:
    """
    Prints FizzBuzz for numbers 1 to n.
    """
    for i in range(1, n + 1):
        if i % 3 == 0:
            print("Fizz", end=" ")
        elif i % 5 == 0:
            print("Buzz", end=" ")
        elif i % 15 == 0:
            print("FizzBuzz", end=" ")
        else:
            print(i, end=" ")
    print()  # Add a newline at the end

if __name__ == "__main__":
    fizz_buzz(100)
```

